final:
module top_module (
    input x,
    input p,
    input m,
    output reg not_r
);
    always @(*) begin
        case ({x, p, m})
            3'b011: not_r = 1'b0;
            3'b000: not_r = 1'b0;
            3'b101: not_r = 1'b0;
            3'b111: not_r = 1'b1;
            3'b100: not_r = 1'b0;
            3'b010: not_r = 1'b0;
            3'b001: not_r = 1'b1;
            3'b110: not_r = 1'b0;
        endcase
    end
endmodule
